# Extract metadata from Annotated
from typing import get_args, get_origin

def get_metadata(hint):
    if get_origin(hint) is Annotated:
        args = get_args(hint)
        return args[0], args[1:]  # (type, metadata_tuple)
    return hint, ()

base_type, metadata = get_metadata(hints['name'])
