# Runtime validation using Annotated metadata
def validate(func, **kwargs):
    hints = get_type_hints(func, include_extras=True)
    for param, hint in hints.items():
        if param == 'return':
            continue
        base, meta = get_metadata(hint)
        value = kwargs.get(param)
        for m in meta:
            if isinstance(m, MinValue) and isinstance(value, (int, float)):
                if value < m.value:
                    raise ValueError(f"{param} must be >= {m.value}")
            if isinstance(m, MaxValue) and isinstance(value, (int, float)):
                if value > m.value:
                    raise ValueError(f"{param} must be <= {m.value}")

