def logged[**P, R](func: Callable[P, R]) -> Callable[P, R]:
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        print(f"Calling {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

# TypeVarTuple (variadic generics) with new syntax
def first_of[*Ts](args: tuple[*Ts]) -> tuple[*Ts]:
    return args

# Generic class with multiple params
class Pair[T, U]:
    def __init__(self, first: T, second: U) -> None:
        self.first = first
        self.second = second

    def swap(self) -> 'Pair[U, T]':
        return Pair(self.second, self.first)

pair = Pair(1, "hello")  # Pair[int, str]
swapped = pair.swap()     # Pair[str, int]

